-- convofinance-platform  ·  04_seed.sql
-- Full seed: 2,261 rows across 14 tables, exported from the live database.
-- banks is inserted first WITH original bank_id values (OVERRIDING SYSTEM
-- VALUE) and the identity sequence is reset, so all foreign keys resolve.
-- Child tables insert without their own id (identity regenerates).
-- cbj_policy_rates is intentionally empty (no data at source).
-- Run after: 01_schema.sql, 02_policies.sql, 03_views.sql
-- =====================================================================



select setval(pg_get_serial_sequence('banks','bank_id'), (select max(bank_id) from banks));

