(15,2025,1518037,886711,1120917,179373,179373,120000,48745,null,null,null,null,14056,117,null,0,null,7.96,0.96,12.5,4.5,null,null,null,null,726,25,'https://www.jcbank.com.jo/uploads/2025/03/2025en.pdf','annual_report','JOD','Smallest bank by assets (15th). Assets JOD 1.52B. Net profit JOD 14.1M (+20.5%). Deposits JOD 1.12B. Net loans JOD 887M. Equity JOD 179M. ROE 7.96%. ROA 0.96%. CAR 12.50% (lowest in sector, at regulatory minimum). EPS 117 fils. 726 employees. JAH premium program. Tejari Tawfeeri prize-linked savings. IFAD agricultural development program. SME: Fast Food, Home Business, Tejari Business, POS Financing. Google Pay enabled. Treasury & Investment segment. Auditor: Deloitte.','2026-06-15T00:45:02.575292+00:00','2026-06-15T05:51:23.295777+00:00'),
(12,2025,3258386,1571644,2385927,518082,532710,200000,128880,null,null,null,null,44500,220,null,18,null,8.6,1.37,19.18,3.8,null,null,null,null,1823,48,'https://bankofjordan.com/en/investor-relations','annual_report','JOD','Assets JOD 3.26B (+3.3%). Net profit JOD 44.5M (+24.9% from JOD 35.3M). Deposits JOD 2.39B. NII JOD 128.88M. Equity JOD 518M (shareholders), JOD 533M total. ROE 8.6%. ROA 1.37%. CAR 19.18%. EPS 220 fils. 18% cash dividend (JOD 36M). 1,823 employees. Retail: 31.7% of portfolio; corporate 27.1%; real estate 12.9%; government 17.6%. BOJ Mobile launched Jordan + Palestine + Iraq (2025). Presence: Jordan, Palestine, Iraq branch, Saudi Arabia branch. Gaza Humanitarian Relief program. Enterprise Content Management (ECM) rollout 2025. Financial Brokerage segment: IPOs, investment trusteeship. Auditor: Deloitte.','2026-06-15T00:45:02.575292+00:00','2026-06-15T05:51:23.295777+00:00'),
