(2,'2026-05-04',2,'fixed',5,null,null,null,1,0.25,4,10,2,null,15,30,60,null,10,1,1,75,150,300,true,0,null,'JOD','https://hbtf.com/uploads/2026/05/fees-and-charges-eng.pdf','Issue date 04-05-2026. Cheque book: 10 cheques JOD 4 (standard), JOD 6 (Edge/Plus/Sayidaty). Returned cheque (NSF) JOD 20/cheque. Returned cheque (technical) JOD 2. Stop cheque JOD 10. Dormant JOD 2/month max JOD 6. Account maintenance JOD 1 if balance <100. Salary transfer: JOD 1 (first 3 months for same entity). ACH branch: JOD 2 (<1K), JOD 3 (1K-5K), JOD 4 (>5K). RTGS branch: JOD 8 (within ceiling), JOD 13 (above). CliQ: JOD 0.06-3.00 sliding scale. Safe box standard: JOD 75-300 annual; virtual branch: JOD 260-700; collateral JOD 250. Loan fee: 1% first year. Early settlement: free if ≤1yr, 1% if >1yr. Late payment salaried: JOD 10 after 5 days. Overdraft interest: 15% JOD / 8% FCY.','2026-06-15T10:38:45.829655+00:00','2026-06-15T13:17:28.801715+00:00'),
(8,'2026-01-01',2,'fixed',5,null,null,null,1,0.25,4,10,2,null,15,30,60,null,10,1,1,50,100,200,true,1,null,'JOD','https://www.ajib.com/sites/default/files/2026-01/Schedule%20of%20Tarrifs%20and%20Fees_Retail%20Banking_EN_Jan%202026_0.pdf','Jan 2026. Tiers: Value / Advantage (min salary JOD 700, rel. balance JOD 2,500) / Prestige (min salary JOD 3,000, rel. balance JOD 20,000) / Digital Banking. Returned cheque NSF JOD 20/first time. Stop cheque JOD 10. Cheque book: 10 leaves JOD 4, 25 leaves JOD 6, 40 leaves JOD 8 (Prestige: free). ACH: JOD 2 (<1K), JOD 3 (1K-5K), JOD 4 (>5K) — Value/Advantage; Prestige: free. RTGS within ceiling: JOD 8, above: JOD 13. Inward ACH: JOD 1 (<1K), JOD 2 (>1K). AJIB Band: JOD 15 issuance. ATM abroad: JOD 2.50/txn. Late payment: JOD 10/installment. Early settlement: free if ≤1yr, 1% if >1yr. Overdraft: 15% daily. FX fee: up to 4.5%.','2026-06-15T10:38:45.829655+00:00','2026-06-15T13:19:43.068547+00:00'),
(4,'2026-01-01',2,'tiered',5,0.25,null,70,1,0.25,0.5,10,2,null,15,30,60,null,10,1,1,50,100,200,null,null,null,'JOD','https://www.capitalbank.jo/-/media/pdfs/banking-tariff/banking-tariff---en.ashx','Cheque book: JOD 0.50/leaf. Returned cheque NSF: JOD 20 (1st), JOD 40 (2nd). Technical return: JOD 2. Stop cheque: JOD 10. Local ACH: JOD 2 (<1K), JOD 3 (1K-5K), JOD 4 (>5K). RTGS: JOD 8 (within ceiling), JOD 13 (above). Intl transfer SHA/BEN: JOD 5 (<1K), JOD 10 (1K-5K), 0.25% max JOD 70 (>5K); OUR: same + JOD 20 correspondent. Inward RTGS: JOD 2. Balance cert: JOD 10. Clearance cert: JOD 25. Signature verify: JOD 5. Dormant: JOD 2/month. FX commission: 0.25%. Loan insurance: JOD 100 (5K-10K), JOD 150 (10K-30K), JOD 300 (>30K). Import LC: 2% p.a. min JOD 70/qtr. Guarantee: 2% p.a. min JOD 25/qtr. Payment guarantee: 4% p.a. min JOD 50/qtr.','2026-06-15T10:38:45.829655+00:00','2026-06-15T13:00:56.444604+00:00'),
(3,'2025-01-01',2,'fixed',5,0.25,null,70,1,0.25,4,10,2,null,15,30,60,null,10,1,1,50,100,200,true,1,null,'JOD','https://www.jkb.com/en/account/saving-accounts','Jordan Kuwait Bank fees (CBJ regulated). Min balance JOD 100. Low balance JOD 1/month. Dormant JOD 2/month. Stop cheque JOD 10. Loan fee 1%. Early settlement 1% if >1yr. JKBCORP+ digital platform. Safe Store Auto available. 0% installment up to 36 months. AMEX + Wearable Mastercard.','2026-06-15T11:09:11.685264+00:00','2026-06-15T13:00:56.444604+00:00'),
(13,'2025-04-01',2,'fixed',5,0.25,null,70,1,0.25,4,10,2,null,15,30,60,null,10,1,1,50,100,200,true,1,null,'JOD','https://www.investbank.jo/media/2025/04/Commission-And-Fees-English.pdf','Invest Bank fees (merged into BaE H2 2025). CBJ regulated. Loan fee 1%. Early settlement 1% if >1yr. PRIME Banking: fee waivers. Auto Safe Deposit Boxes. iCash, iVoucher, CliQ.','2026-06-15T11:09:11.685264+00:00','2026-06-15T13:00:56.444604+00:00');
INSERT INTO bank_announcements (bank_id, announcement_date, category, headline_en, headline_ar, summary_en, source_url, source_type, fiscal_year, is_verified, tags, notes, created_at, updated_at, summary_ar) VALUES
(13,'2025-06-25','merger_acquisition','Invest Bank and Bank al Etihad Merger Approved by Regulators',null,'The merger between Invest Bank (formerly Jordan Investment Bank) and Bank al Etihad received regulatory approval from the Central Bank of Jordan and relevant authorities. Both bank homepages prominently display the merger announcement. Combined entity expected to have assets exceeding JOD 3.6 billion.','https://www.investbank.jo','website',2025,true,ARRAY['merger','bank-al-etihad','invest-bank','cbj'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(5,'2025-06-25','merger_acquisition','Bank al Etihad Merger with Invest Bank: Strategic Combination',null,'Bank al Etihad is merging with Invest Bank to create one of Jordan largest banking groups. The merger represents the largest banking consolidation in Jordan in recent years. Assets of the combined entity will exceed JOD 3.6 billion.','https://www.bankaletihad.com','website',2025,true,ARRAY['merger','invest-bank','bank-al-etihad'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(6,'2026-03-01','dividend','Cairo Amman Bank Distributes 7% Cash Dividend for FY2025',null,'Cairo Amman Bank announced a 7% cash dividend distribution to shareholders for fiscal year 2025. Net profit grew 64.5% to JOD 26.5M vs JOD 14.3M in 2024.','https://www.cab.jo/investor-relations','agm_press_release',2025,true,ARRAY['dividend','cab'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(4,'2026-02-01','strategic','Capital Bank Releases 4th Sustainability Report and 17% Cash Dividend',null,'Capital Bank announced its 4th annual sustainability report alongside a 17% cash dividend for FY2025, reflecting strong financial performance.','https://www.capitalbank.jo','website',2025,true,ARRAY['dividend','sustainability','capital-bank'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(2,'2025-11-01','product_launch','Housing Bank Launches Iskan Business Corporate E-Banking Platform',null,'Housing Bank (HBTF) launched its new Iskan Business corporate e-banking platform, targeting corporate clients with enhanced digital banking capabilities.','https://www.hbtf.com','website',2025,true,ARRAY['digital','corporate-banking','hbtf'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(7,'2025-06-01','strategic','Jordan Ahli Bank Expands ESG and Green Banking Initiatives',null,'Jordan Ahli Bank launched dedicated ESG and green banking sections, reinforcing its commitment to sustainable finance. The bank grew total assets 5.6% to JOD 3.72B with net profit of JOD 21.3M (+19.4%).','https://ahli.com','website',2025,true,ARRAY['esg','green-banking','ahli'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(6,'2025-09-01','strategic','Cairo Amman Bank Partners with CrowdStrike for Cybersecurity',null,'Cairo Amman Bank announced a strategic cybersecurity partnership with CrowdStrike, reinforcing its digital security infrastructure.','https://www.cab.jo','website',2025,true,ARRAY['cybersecurity','digital','cab'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(10,'2025-07-01','strategic','Safwa Islamic Bank Increases Paid-Up Capital from JOD 120M to JOD 150M',null,'Safwa Islamic Bank completed a capital increase from JOD 120 million to JOD 150 million following CBJ approval and EGM resolution, strengthening its capital base.','https://www.safwabank.com','website',2025,true,ARRAY['capital-increase','safwa','islamic'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(3,'2026-03-01','financial_results','Jordan Kuwait Bank Posts JOD 151.1M Net Profit for FY2025',null,'JKB (KIPCO Group) reported net profit of JOD 151.1M for 2025, down from JOD 194.3M in 2024 due to interest rate environment changes. Total assets JOD 5.46B. CAR 21.92%. ROE 16.43%.','https://www.jkbank.com','annual_report',2025,true,ARRAY['results','jkb','kipco'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(4,'2026-03-01','financial_results','Capital Bank Records Record Profit of JOD 94.2M for FY2025',null,'Capital Bank achieved record net profit growth of 34.2% to JOD 94.2M. Total assets JOD 8.4B. Declared 17% cash dividend. Named Best Bank in Jordan and Best Banking App in Jordan.','https://www.capitalbank.jo','annual_report',2025,true,ARRAY['results','capital-bank','dividend','award'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(2,'2026-04-01','financial_results','Housing Bank (HBTF) Reports JOD 157.7M Net Profit for FY2025',null,'HBTF reported net profit of JOD 157.7M for 2025. Total assets reached JOD 9.4B with 11.2% sector market share. Deposits JOD 5.9B. EPS 492 fils. Cash dividend JOD 0.30/share.','https://www.hbtf.com','annual_report',2025,true,ARRAY['results','hbtf','dividend'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(8,'2026-03-01','financial_results','AJIB Reports JOD 18M Net Profit with Record Low NPL of 2.57%',null,'AJIB achieved net profit of JOD 18M for 2025 with NPL ratio of 2.57%, the lowest in recent years. Total assets JOD 2.76B. CAR 16.38%.','https://www.ajib.com','annual_report',2025,true,ARRAY['results','ajib','asset-quality'],null,'2026-06-15T00:45:02.575292+00:00','2026-06-15T00:45:02.575292+00:00',null),
(9,'2026-03-01','financial_results','Jordan Islamic Bank Posts JOD 71.1M Net Profit for FY2025',null,'Jordan Islamic Bank (47th annual report) achieved net profit of JOD 71.1M for 2025. Total on-balance assets JOD 6.79B, total assets including off-balance JOD 7.69B. CAR 19.21%. EPS 356 fils. 86 branches and 19 offices across Jordan.','https://www.jordanislamicbank.com/ar/annual-reports','annual_report',2025,true,ARRAY['results','jordan-islamic-bank','islamic'],null,'2026-06-15T00:59:31.314077+00:00','2026-06-15T00:59:31.314077+00:00',null),
(5,'2026-04-01','merger_acquisition','Bank al Etihad + Invest Bank Combined Entity Reports JOD 12.46B Assets',null,'Post-merger Bank al Etihad consolidated financial statements show total assets of JOD 12.46B (+49.2%), customer deposits JOD 9.41B (+46.9% with 13.77% sector share), net profit JOD 69M (+57%), equity JOD 780M (+57.4%). CAR 16.24%. ROE 10.8%. The merger creates one of Jordan largest banking groups.','https://websitev3-cms-cdn.bankaletihad.com/2026/04/433801-BaE-Annual-Report-2025-Ar-23-Final.pdf','annual_report',2025,true,ARRAY['results','merger','bank-al-etihad','invest-bank'],null,'2026-06-15T00:59:31.314077+00:00','2026-06-15T00:59:31.314077+00:00',null),
(3,'2026-03-01','dividend','JKB Approves 18% Cash Dividend for FY2025',null,'Jordan Kuwait Bank (KIPCO Group) approved 18% cash dividend for FY2025. Net profit JOD 151.1M (ROE 16.43%, CAR 21.92%, EPS 595 fils). Total equity JOD 952M.','https://www.jkb.com/en/news','agm_press_release',2025,true,ARRAY['dividend','jkb','kipco'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(5,'2026-03-07','strategic','Bank al Etihad Q4 2025 Investor Presentation: 107 Branches, 3,034 Employees, USD 1.36B Market Cap',null,'Q4 2025 investor presentation reveals combined entity metrics: 107 Jordan + 1 Iraq branches, 3,034 employees, CASA 35.9%, LCR 309.31%, market cap USD 1.362B, CAR 16.24%, CET1 11.8%.','https://websitev3-cms-cdn.bankaletihad.com/2026/03/Investor-Presentation-Q4-2025.pdf','strategic',2025,true,ARRAY['bae','investor-presentation','merger'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(5,'2026-02-18','dividend','Bank al Etihad Recommends 10% Cash Dividend + 7.6% Bonus Shares for FY2025',null,'BaE board recommends 10% cash dividend and 7.6% bonus shares (capital to rise to JOD 350M). Net profit JOD 85.3M (+57%). Subject to regulatory and shareholder approvals.','https://www.bankaletihad.com/en/investor-news/','agm_press_release',2025,true,ARRAY['bae','dividend','bonus-shares'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(9,'2026-02-12','dividend','Jordan Islamic Bank Recommends JOD 50M Cash Dividend (25%) for FY2025',null,'JIB board recommended JOD 50M cash dividend (25% of JOD 200M capital) for FY2025. Pre-tax profit JOD 113.6M. Net profit JOD 71.1M. ROE 12.4%. CAR 19.3%. NPF 2.5%. EPS 356 fils. AGM 27 Apr 2026.','https://www.jordanislamicbank.com/en/news/jordan-islamic-banks-profits-rise-to-jd-1136-million-before-tax-for-the-year-2025','agm_press_release',2025,true,ARRAY['jib','dividend','islamic'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(7,'2025-06-01','product_launch','Jordan Ahli Bank Launches Qawn — Jordan''s First Social Payment App',null,'Jordan Ahli Bank launched Qawn, Jordan''s first social payment app combining chat with payments. iOS and Android. Serves individuals and merchants. Distinctive P2P and merchant payment features.','https://ahli.com','website',2025,true,ARRAY['ahli','digital','fintech','qawn'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(4,'2026-05-03','financial_results','Capital Bank Q1 2026: JOD 50M Net Profit, Assets JOD 8.21B',null,'Capital Bank Q1 2026: net profit JOD 50.0M (+1.7% vs Q1 2025 JOD 49.2M). Total assets JOD 8.21B. Deposits JOD 5.86B. Equity JOD 756.5M (+4.41%). NII JOD 59.5M. AGM 3 May 2026.','https://www.capitalbank.jo/en/personal/about-us/investor-relations','financial_results',2026,true,ARRAY['capital-bank','q1-2026','results'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(4,'2026-04-01','strategic','Capital Bank Wins Best Green Finance Initiative Jordan 2026',null,'Capital Bank received Best Green Finance Initiative in Jordan 2026 (Global Business & Finance). Also won Best Mobile Banking App Middle East 2026 and Best Wealth Management Services Jordan (IBM Awards).','https://www.capitalbank.jo/en/personal/about-us','website',2026,true,ARRAY['capital-bank','esg','green-finance','strategic'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(2,'2025-07-27','financial_results','Housing Bank Reports JOD 80.1M Net Profit for H1 2025',null,'HBTF H1 2025: net profit JOD 80.1M. Net credit facilities JOD 4.8B (+5.9%). Customer deposits JOD 6.1B (+2%). Total equity JOD 1.4B. CAR 18.6%. CEO: Ammar Al-Safadi.','https://hbtf.com/en/news/net-profits-h1-2025','other',2025,true,ARRAY['hbtf','h1-2025','results'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(12,'2026-03-16','dividend','Bank of Jordan Distributes 18% Cash Dividend (JOD 36M) for FY2025',null,'BOJ distributed 18% cash dividend = JOD 36M for FY2025. Net profit JOD 44.5M (+24.9%). EPS 220 fils. CAR 19.18%. NII JOD 128.88M.','https://bankofjordan.com','agm_press_release',2025,true,ARRAY['boj','dividend'],null,'2026-06-15T05:51:23.295777+00:00','2026-06-15T05:51:23.295777+00:00',null),
(7,'2026-04-28','leadership_change','Jordan Ahli Bank Appoints Ahmad Abu Eideh as CEO & General Manager',null,'Jordan Ahli Bank appointed Ahmad Abu Eideh as CEO and General Manager effective 01 May 2026, succeeding Dr. Ahmad Al-Hussein. Abu Eideh brings 30+ years experience including Standard Chartered and regional banks.','https://ahli.com/after-a-distinguished-career-jordan-ahli-bank-bids-farewell-to-ceo-dr-ahmad-al-hussein-and-announces-the-appointment-of-ahmad-abu-eideh-to-lead-the-next-phase/','press_release',2026,true,ARRAY['ahli','ceo','leadership','ahmad-abu-eideh'],null,'2026-06-15T17:57:44.198223+00:00','2026-06-15T17:57:44.198223+00:00',null),
